
// CPU pixel/vector utilities (buffers, blends, gradients, paths). Used app-wide as PixelUtil.
function PixelUtil() {}

PixelUtil.fx = {};

PixelUtil.awk = {};

PixelUtil.scratchCanvasPool = function() {
	var l = [64, 64, 128, 256, 512, 1024, 2048],
		d = [];
	for (var A = 0; A < l.length; A++) {
		var G = l[A],
			b = document.createElement("canvas");
		b.width = G;
		b.height = G;
		d.push(b.getContext("2d", { willReadFrequently: true }))
	}
	return d
}();

PixelUtil.getScratch2dContext = function(l, d) {
	var G, b = PixelUtil.scratchCanvasPool,
		A = 1,
		V = Math.max(l, d);
	while (A < b.length && V > b[A].canvas.width) A++;
	if (A == b.length) {
		G = b[0];
		var Q = G.canvas;
		Q.width = l;
		Q.height = d
	} else {
		G = b[A];
		G.clearRect(0, 0, l, d)
	}
	return G
};

PixelUtil.buildIntegralImage = function(l, d, G) {
	var b = new Uint32Array(d * G);
	b[0] = l[0];
	for (var V = 1; V < d; V++) b[V] = b[V - 1] + l[V];
	for (var Q = 1; Q < G; Q++) {
		var A = Q * d;
		b[A] = b[A - d] + l[A];
		for (var V = 1; V < d; V++) b[A + V] = l[A + V] + b[A + V - 1] + b[A + V - d] - b[A + V - d - 1]
	}
	return b
};

PixelUtil.integralRectSum = function(l, d, G, b, V, Q) {
	var t = (V - 1) * d,
		I = Q * d;
	return l[I + b] - l[I + G - 1] - l[t + b] + l[t + G - 1]
};

PixelUtil.isSimpleFlatImage = function(l, d, G) {
	var b = {},
		V = 0,
		Q = 0,
		t = new Uint32Array(l.buffer),
		I = t.length,
		y = Date.now();
	for (var e = 1; e < G - 1; e++)
		for (var M = 1; M < d - 1; M++) {
			var R = e * d + M,
				J = t[R];
			if (J >>> 24 < 230) Q++;
			if (b[J] == null) {
				b[J] = true;
				V++
			}
		}
	if (Q != 0 || V < 20) return false;
	return true
};

PixelUtil.fillCheckerboard = function(l, d, G, b, V, Q) {
	if (V == null) V = Q = 0;
	b = Math.log(b) / Math.log(2);
	b = Math.round(b);
	for (var A = 0; A < G; A++)
		for (var t = 0; t < d; t++) {
			var I = A * d + t << 2,
				y = PixelUtil.checkerboardSample(A + Q, t + V, b);
			l[I] = l[I + 1] = l[I + 2] = y;
			l[I + 3] = 255
		}
};

PixelUtil.checkerboardSample = function(A, l, d) {
	return 255 - ((A >>> d) + (l >>> d) & 1) * 51
};

PixelUtil.intToRgb = function(l) {
	return {
		o: l >>> 16 & 255,
		J: l >>> 8 & 255,
		k: l & 255
	}
};

PixelUtil.intToHex6 = function(l) {
	var d = l.toString(16);
	while (d.length < 6) d = "0" + d;
	return d
};

PixelUtil.hex6ToInt = function(l) {
	return parseInt(l, 16)
};

PixelUtil.rgbObjectLuminance = function(l) {
	return .3 * l.o + .59 * l.J + .11 * l.k
};

PixelUtil.rgbObjectChroma = function(l) {
	return Math.max(l.o, l.J, l.k) - Math.min(l.o, l.J, l.k)
};

PixelUtil.luminanceRgb = function(l, d, G) {
	return .3 * l + .59 * d + .11 * G
};

PixelUtil.chromaRgb = function(l, d, G) {
	return Math.max(l, d, G) - Math.min(l, d, G)
};

PixelUtil.shortestAngleWrap = function(l, d) {
	var G = d - l,
		b = Math.abs(G),
		V = G - 1,
		Q = G + 1;
	if (Math.abs(V) < b) G = V;
	else if (Math.abs(Q) < b) G = Q;
	return G
};

PixelUtil.linearToSrgb = function(l) {
	return l < .0031308 ? 12.92 * l : 1.055 * Math.pow(l, 1 / 2.4) - .055
};

PixelUtil.srgbToLinear = function(l) {
	return l < .04045 ? l / 12.92 : Math.pow((l + .055) / 1.055, 2.4)
};

PixelUtil.rgbaToYuv420 = function(l, d) {
	var G = Math.min(l.length, d.length);
	for (var A = 0; A < G; A += 4) {
		var b = l[A],
			V = l[A + 1],
			Q = l[A + 2];
		d[A] = 16 + Math.floor(65.481 / 255 * b + 128.553 / 255 * V + 24.966 / 255 * Q + .5);
		d[A + 1] = 128 - Math.floor(37.797 / 255 * b - 74.203 / 255 * V + 112 / 255 * Q + .5);
		d[A + 2] = 128 + Math.floor(112 / 255 * b - 93.786 / 255 * V - 18.214 / 255 * Q + .5);
		d[A + 3] = l[A + 3]
	}
};

PixelUtil.rgbToHsv = function(l, d, G) {
	var b, V, Q, t = Math.max(l, d, G),
		I = Math.min(l, d, G);
	Q = t;
	if (t != 0) V = (t - I) / t;
	else V = 0;
	if (V == 0) b = 0;
	else {
		var y = t - I,
			e = (t - l) / y,
			M = (t - d) / y,
			R = (t - G) / y;
		if (l == t) b = R - M;
		else if (d == t) b = 2 + e - R;
		else b = 4 + M - e;
		b *= 1 / 6;
		if (b < 0) b = b + 1
	}
	return {
		Tq: b,
		Lm: V,
		k: Q
	}
};

PixelUtil.hsvToRgb = function(l, d, G) {
	var b = 0,
		V = 0,
		Q = 0;
	if (d == 0) b = V = Q = G;
	else {
		var t = (l - Math.floor(l)) * 6,
			I = Math.floor(t),
			y = t - Math.floor(t),
			e = G * (1 - d),
			M = G * (1 - d * y),
			R = G * (1 - d * (1 - y));
		switch (I) {
			case 0:
				b = G;
				V = R;
				Q = e;
				break;
			case 1:
				b = M;
				V = G;
				Q = e;
				break;
			case 2:
				b = e;
				V = G;
				Q = R;
				break;
			case 3:
				b = e;
				V = M;
				Q = G;
				break;
			case 4:
				b = R;
				V = e;
				Q = G;
				break;
			case 5:
				b = G;
				V = e;
				Q = M;
				break
		}
	}
	return {
		o: b,
		J: V,
		k: Q
	}
};

PixelUtil.rgbToHsl = function(l, d, G) {
	var b = Math.max(l, d, G),
		V = Math.min(l, d, G),
		Q = 0,
		t = 0,
		I = (b + V) * .5;
	if (b != V) {
		var y = b - V;
		t = I > .5 ? y / (2 - (b + V)) : y / (b + V);
		switch (b) {
			case l:
				Q = (d - G) / y + (d < G ? 6 : 0);
				break;
			case d:
				Q = (G - l) / y + 2;
				break;
			case G:
				Q = (l - d) / y + 4;
				break
		}
		Q *= 1 / 6
	}
	return {
		Tq: Q,
		Lm: t,
		_Z: I
	}
};

PixelUtil.hslToRgb = function(l, d, G) {
	var b, V, Q;
	if (d == 0) b = V = Q = G;
	else {
		var t = G < .5 ? G * (1 + d) : G + d - G * d,
			I = 2 * G - t;
		b = PixelUtil.hslHueComponent(I, t, l + 1 / 3);
		V = PixelUtil.hslHueComponent(I, t, l);
		Q = PixelUtil.hslHueComponent(I, t, l - 1 / 3)
	}
	return {
		o: b,
		J: V,
		k: Q
	}
};

PixelUtil.hslHueComponent = function(l, d, G) {
	if (G < 0) G += 1;
	if (G > 1) G -= 1;
	if (G < 1 / 6) return l + (d - l) * 6 * G;
	if (G < 1 / 2) return d;
	if (G < 2 / 3) return l + (d - l) * (2 / 3 - G) * 6;
	return l
};

PixelUtil.rgbToHsb = function(l, d, G) {
	var b = Math.max(l, d, G),
		V = Math.min(l, d, G),
		Q, t, I = b,
		y = b - V;
	t = b == 0 ? 0 : y / b;
	if (b == V) Q = 0;
	else {
		switch (b) {
			case l:
				Q = (d - G) / y + (d < G ? 6 : 0);
				break;
			case d:
				Q = (G - l) / y + 2;
				break;
			case G:
				Q = (l - d) / y + 4;
				break
		}
		Q *= 1 / 6
	}
	return {
		Tq: Q,
		Lm: t,
		qv: I
	}
};

PixelUtil.hsbToRgb = function(l, d, G) {
	var b, V, Q, A, t, I, y, e;
	A = Math.floor(l * 6);
	t = l * 6 - A;
	I = G * (1 - d);
	y = G * (1 - t * d);
	e = G * (1 - (1 - t) * d);
	switch (A % 6) {
		case 0:
			b = G, V = e, Q = I;
			break;
		case 1:
			b = y, V = G, Q = I;
			break;
		case 2:
			b = I, V = G, Q = e;
			break;
		case 3:
			b = I, V = y, Q = G;
			break;
		case 4:
			b = e, V = I, Q = G;
			break;
		case 5:
			b = G, V = I, Q = y;
			break
	}
	return {
		o: b,
		J: V,
		k: Q
	}
};

PixelUtil.labGammaTables = function() {
	var l = [],
		d = [];
	for (var A = 0; A < 8e3; A++) {
		var G = A * (1 / 4e3);
		l[A] = PixelUtil.srgbToLinear(G);
		d[A] = G > .008856 ? Math.pow(G, 1 / 3) : (903.3 * G + 16) * (1 / 116)
	}
	return [l, d]
}();

PixelUtil.rgbToLab = function(l, d, G, b) {
	if (b == null) b = [.9642, 1, .8249];
	var V = PixelUtil.labGammaTables[0],
		Q = PixelUtil.labGammaTables[1];
	l = V[~~(.5 + l * (4e3 / 255))];
	d = V[~~(.5 + d * (4e3 / 255))];
	G = V[~~(.5 + G * (4e3 / 255))];
	var t = PixelUtil.mat4.gG,
		I = t[0] * l + t[1] * d + t[2] * G,
		y = t[4] * l + t[5] * d + t[6] * G,
		e = t[8] * l + t[9] * d + t[10] * G;
	I = I * (1 / b[0]);
	y = y * (1 / b[1]);
	e = e * (1 / b[2]);
	return PixelUtil.xyzToLab(I, y, e)
};

PixelUtil.xyzToLab = function(l, d, G) {
	var b = PixelUtil.labGammaTables[1],
		V = b[~~(.5 + l * 4e3)],
		Q = b[~~(.5 + d * 4e3)],
		t = b[~~(.5 + G * 4e3)];
	return {
		Hm: 116 * Q - 16,
		aS: 500 * (V - Q),
		k: 200 * (Q - t)
	}
};

PixelUtil.labToRgb = function(l, d, G) {
	var b = 903.3,
		V = .008856,
		Q = (l + 16) / 116,
		t = Q * Q * Q,
		I = Q - G / 200,
		y = I * I * I,
		e = d / 500 + Q,
		M = e * e * e,
		R = y > V ? y : (116 * I - 16) / b,
		J = t > V ? t : (116 * Q - 16) / b,
		n = M > V ? M : (116 * e - 16) / b,
		r = n * 96.42,
		T = J * 100,
		j = R * 82.49,
		g = PixelUtil.mat4.Uz(PixelUtil.mat4.lq, [r / 100, T / 100, j / 100, 0]);
	for (var A = 0; A < 4; A++) g[A] = Math.max(0, Math.min(255, PixelUtil.linearToSrgb(g[A]) * 255));
	return {
		o: g[0],
		J: g[1],
		k: g[2]
	}
};

PixelUtil.labBlendWeight = function(l, d, G, b, V) {
	var Q = l.Hm,
		t = l.aS,
		I = l.k,
		y = (Q < d.Hm ? d.Hm - Q : G.Hm < Q ? G.Hm - Q : 0) * (1 / 100),
		e = (t < d.aS ? d.aS - t : G.aS < t ? G.aS - t : 0) * (1 / 116),
		M = (I < d.k ? d.k - I : G.k < I ? G.k - I : 0) * (1 / 116),
		R = Math.sqrt(y * y + e * e + M * M) * 1.35;
	return R <= b ? Math.min(1, 1.17 * (1 - R * V)) : 0
};

