				Z = (T >>> 8 & 255) << 2,
				B = (T & 255) << 2,
				a = (j >>> 16 & 255) << 1,
				m = (j >>> 8 & 255) << 1,
				p = (j & 255) << 1,
				c = (g >>> 16 & 255) << 2,
				v = (g >>> 8 & 255) << 2,
				i = (g & 255) << 2,
				z = (Y >>> 16 & 255) << 1,
				P = (Y >>> 8 & 255) << 1,
				C = (Y & 255) << 1,
				h = k >>> 16 & 255,
				L = k >>> 8 & 255,
				U = k & 255,
				S = (F >>> 16 & 255) << 1,
				E = (F >>> 8 & 255) << 1,
				x = (F & 255) << 1,
				K = (D >>> 16 & 255) << 2,
				u = (D >>> 8 & 255) << 2,
				bC = (D & 255) << 2,
				O = (q >>> 16 & 255) << 1,
				$ = (q >>> 8 & 255) << 1,
				gX = (q & 255) << 1,
				_ = (H >>> 16 & 255) << 2,
				jI = (H >>> 8 & 255) << 2,
				iw = (H & 255) << 2,
				hn = 0,
				jq = 0,
				iv = 0;
