PixelUtil.textWarp.a7c = function(l, d, G, b) {
	for (var A = 0; A < l.length; A += 2) {
		var V = l[A],
			Q = l[A + 1],
			t = (V - d.x) / d.m,
			I = (Q - d.y) / d.n,
			y = (1 - G) / 2,
			e = 1 - y,
			M = y + t * (e - y);
		I = .5 + (I - .5) * M * 2;
		var R = (1 - b) / 2,
			J = 1 - R,
			n = R + I * (J - R);
		t = .5 + (t - .5) * n * 2;
		V = d.x + t * d.m;
		Q = d.y + I * d.n;
		l[A] = V;
		l[A + 1] = Q
	}
};

